迭代动态规划计算斐波那契数列.code_snippet:
def fibonacci(n):
    if n <= 1:
        return n
    prev, curr = 0, 1
    for i in range(2, n + 1):
        prev, curr = curr, prev + curr
    return curr

斐波那契数列前 n 项和计算.code_snippet:
def fibonacci_sum(n):
    """返回斐波那契数列前 n 项的和。"""
    if n <= 0:
        return 0
    # 计算 F(n+2)
    a, b = 1, 1  # F(1) 和 F(2)
    for _ in range(3, n + 3):  # 迭代到 F(n+2)
        a, b = b, a + b
    return b - 1  # S(n) = F(n+2) - 1
